// WebGPU 命令录制的标准流程
// 1. 创建命令编码器
const encoder = device.createCommandEncoder();

// 2. 开始渲染 Pass
const passEncoder = encoder.beginRenderPass(renderPassDescriptor);

// 3. 录制渲染命令
passEncoder.setPipeline(pipeline);
passEncoder.setBindGroup(0, bindGroup);
passEncoder.setVertexBuffer(0, vertexBuffer);
passEncoder.setIndexBuffer(indexBuffer, 'uint16');
passEncoder.drawIndexed(6, 100);  // 6个索引, 100个实例

// 4. 结束渲染 Pass
passEncoder.end();

// 5. 完成命令编码
const commandBuffer = encoder.finish();

// 6. 提交到 GPU 队列
device.queue.submit([commandBuffer]);

// WebGPU drawIndexed 方法
passEncoder.drawIndexed(
    indexCount,      // 每个实例的索引数量
    instanceCount,   // 实例数量
    firstIndex,      // 起始索引
    baseVertex,      // 基础顶点偏移
    firstInstance    // 起始实例索引
);

// 2D 精灵批量渲染的典型调用
// 6个索引（2个三角形组成一个四边形），100个实例
passEncoder.drawIndexed(6, 100, 0, 0, 0);

// 实例属性的顶点缓冲区布局
const instanceBufferLayout: GPUVertexBufferLayout = {
    arrayStride: 64,  // 每个实例的数据大小（如 mat4x4）
    stepMode: 'instance',  // 关键：每个实例而非每个顶点更新
    attributes: [
        // 实例变换矩阵（4 个 vec4）
        { format: 'float32x4', offset: 0,  shaderLocation: 1 },
        { format: 'float32x4', offset: 16, shaderLocation: 2 },
        { format: 'float32x4', offset: 32, shaderLocation: 3 },
        { format: 'float32x4', offset: 48, shaderLocation: 4 },
    ],
};

// WebGPUPipelineState.prepare() 中的关键代码
currBufferLayout.arrayStride = gpuAttr.stride;
currBufferLayout.stepMode = attr.isInstanced ? 'instance' : 'vertex';

// StaticVBAccessor 的工作原理
// 预分配 64KB 的顶点缓冲区
const accessor = new StaticVBAccessor(device, vfmtPosUvColor, 65536);

// 分配子区域（返回偏移量和大小）
const { offset, size } = accessor.alloc(vertexCount);

// 写入顶点数据
buffer.update(vertexData, offset);

// 使用偏移量绘制
passEncoder.drawIndexed(indexCount, 1, 0, offset / vertexStride);

// DescriptorSetCache 的缓存策略
class DescriptorSetCache {
    private _cache: Map<number, DescriptorSet> = new Map();

    getDescriptorSet(hash: number, createFn: () => DescriptorSet): DescriptorSet {
        if (this._cache.has(hash)) {
            return this._cache.get(hash)!;
        }
        const ds = createFn();
        this._cache.set(hash, ds);
        return ds;
    }
}

